class coordinate {
  constructor(x, y) {
    this.x = x;
    this.y = y;
  }
}

const palindrome = "levelup";
const lowercaseWords = ["level", "up", "low"];

function checkLowercaseWords(words) {
  const count = new Map();
  for (const word of words) {
    if (count.has(word)) {
      count.set(word, count.get(word) + 1);
    } else {
      count.set(word, 1);
    }
  }
  return Array.from(count.entries()).filter(([word, count]) => count <= 3);
}

const validWords = checkLowercaseWords(lowercaseWords);
console.log(validWords);

const result = "the coordinates are " + validWords.join(" and ") + " with a palindrome: " + palindrome;
console.log(result);

